import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Eye, EyeOff } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

function FitnationLogo({ size = 48 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
      <circle cx="50" cy="50" r="44" stroke="url(#lring)" strokeWidth="5" fill="none" />
      <rect x="4" y="46" width="18" height="8" rx="3" fill="url(#lbarb)" />
      <rect x="2"  y="42" width="6"  height="16" rx="2" fill="#90caf9" />
      <rect x="78" y="46" width="18" height="8" rx="3" fill="url(#lbarb)" />
      <rect x="92" y="42" width="6"  height="16" rx="2" fill="#90caf9" />
      <polygon points="50,18 28,75 72,75" fill="url(#ltri)" />
      <polygon points="50,40 40,65 60,65" fill="#0a0a0f" />
      <defs>
        <linearGradient id="ltri" x1="28" y1="18" x2="72" y2="75" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#38bdf8" /><stop offset="100%" stopColor="#1565c0" />
        </linearGradient>
        <linearGradient id="lring" x1="0" y1="0" x2="100" y2="100" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#90caf9" /><stop offset="100%" stopColor="#455a64" />
        </linearGradient>
        <linearGradient id="lbarb" x1="0" y1="0" x2="1" y2="0" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#90caf9" /><stop offset="100%" stopColor="#607d8b" />
        </linearGradient>
      </defs>
    </svg>
  );
}

export default function LoginPage() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome back, ${user.name}!`);
      if (user.role === 'admin' || user.role === 'trainer') navigate('/admin');
      else navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center px-4 bg-grid">
      <div className="absolute inset-0 bg-gradient-to-br from-orange-900/20 via-transparent to-red-900/10" />

      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="relative z-10 w-full max-w-md"
      >
        <div className="glass rounded-2xl p-8 border border-orange-500/10">
          {/* Logo */}
          <div className="text-center mb-8">
            <div className="mx-auto mb-3 flex justify-center">
              <FitnationLogo size={60} />
            </div>
            <h1 className="gym-font text-3xl text-white">FITNATION <span className="gradient-text">BY AJEET</span></h1>
            <p className="text-sky-400 text-xs tracking-widest mt-1">UNITING A HEALTHIER WORLD</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="text-gray-400 text-sm block mb-1.5">Email</label>
              <input
                className="input-dark"
                type="email"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                placeholder="your@email.com"
                required
              />
            </div>
            <div>
              <label className="text-gray-400 text-sm block mb-1.5">Password</label>
              <div className="relative">
                <input
                  className="input-dark pr-10"
                  type={showPass ? 'text' : 'password'}
                  value={form.password}
                  onChange={e => setForm({ ...form, password: e.target.value })}
                  placeholder="••••••••"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPass(!showPass)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-white transition-colors"
                >
                  {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={loading} className="btn-fire w-full py-3.5 text-base flex items-center justify-center gap-2">
              {loading ? <span className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" /> : 'Sign In'}
            </button>
          </form>

          <p className="text-center text-gray-500 text-sm mt-6">
            Not a member yet?{' '}
            <a href="/enquiry" className="text-orange-400 hover:underline">Enquire to join</a>
          </p>
        </div>
      </motion.div>
    </div>
  );
}
